mapper.select:

select



from ac_overtime_leave aol
     where aol.id = #{id,jdbcType=BIGINT}

mapper.sql:
select temp.*, pej.job_name AS pe_job_name, peen.entry_time AS entry_time, pel.quit_time AS quit_time, fdev.ext_dept_name as pe_dept_name, fdev.ext_department_name as pe_department, fdev.ext_team_name as pe_team, pe.leave_flag as pe_leave_flag from ( select sum(isnull(ol.working_day_overtime, 0)) AS working_day_overtime, sum(isnull(ol.rest_day_overtime, 0) ) AS rest_day_overtime, sum(isnull(ol.holiday_overtime, 0)) as holiday_overtime, sum( isnull(ol.off_hours, 0) ) AS off_hours, sum( isnull(ol.annual_leave, 0) ) AS annual_leave, sum( isnull(ol.compassionate_leave, 0) ) AS compassionate_leave, sum( isnull(ol.sick_leave, 0) ) AS sick_leave, sum( isnull(ol.marriage_holiday, 0) ) AS marriage_holiday, sum( isnull(ol.maternity_leave, 0) ) AS maternity_leave, sum( isnull(ol.paternity_leave, 0) ) AS paternity_leave, sum( isnull(ol.bereavement_leave, 0) ) AS bereavement_leave, sum( isnull(ol.work_related_injury_leave, 0) ) AS work_related_injury_leave, sum( isnull(ol.working_hours, 0) ) AS working_hours, sum( isnull(ol.family_planning_leave, 0) ) AS family_planning_leave, sum( isnull(ol.public_holiday, 0) ) AS public_holiday,
sum( isnull(ol.total_working_hours, 0) ) AS total_working_hours, sum( isnull(ol.total_over_time, 0) ) AS total_over_time, ol.pe_work_card, ol.pe_name
from v_over_time ol
where 1 = 1
and ol.date BETWEEN #{criteria.dateFrom, jdbcType = DATE} and #{criteria.dateTo, jdbcType = DATE}
GROUP BY ol.pe_work_card, ol.pe_name ) as temp left join pm_employee pe on RIGHT ( cast( '000000' + rtrim( pe.work_card) AS VARCHAR ), 6 ) = RIGHT ( cast( '000000' + rtrim( temp.pe_work_card) AS VARCHAR ), 6 ) and pe.enabled_flag = 1
LEFT JOIN pm_employee_job pej ON pej.employee_id = pe.id AND pej.enabled_flag = 1 AND pej.job_main_flag = 1 LEFT JOIN pm_employee_leaveoffice pel ON pel.employee_id = pe.id AND pel.enabled_flag = 1 left outer join fnd_dept_ext_v fdev on pej.dept_id = fdev.id and fdev.enabled_flag = 1 and fdev.deleted_flag = 0 outer apply ( select top(1) peen_ap.* from pm_employee_entry peen_ap where peen_ap.employee_id = pe.id AND peen_ap.enabled_flag = 1 ) peen where isnull(pel.quit_time, getdate()) > #{criteria.dateFrom, jdbcType = DATE}
and pe_work_card ${criteria.symbol} #{criteria.value, jdbcType = VARCHAR}
and pe_name ${criteria.symbol} #{criteria.value, jdbcType = VARCHAR}
and fdev.ext_dept_name ${criteria.symbol} #{criteria.value, jdbcType = VARCHAR}
and fdev.ext_department_name ${criteria.symbol} #{criteria.value, jdbcType = VARCHAR}
and fdev.ext_team_name ${criteria.symbol} #{criteria.value, jdbcType = VARCHAR}
and exists ( select 1 from pm_employee_job pej where pej.enabled_flag = 1 and pej.job_main_flag = 1 and pej.employee_id = pe.id and pej.dept_id in (
#{item}
) )
